class Trie:
    def countNodes(self, s: str, caseSensitive: bool) -> int:
        count = 0
        root = {'children': {}}
        for char in s:
            node = root
            if char in node['children']:
                node = node['children'][char]
                node['count'] += 1
            else:
                node['children'][char] = {'count': 1, 'children': {}}
                node = node['children'][char]
        return count + len(root['children'])

solutions.cpp:
class Trie {
public:
    int countNodes(String s, bool caseSensitive) {
        int count = 0;
        root = {'children': {}};
        for (int i = 0; i < s.length(); i++) {
            char c = s[i];
            if (caseSensitive) {
                count += 1;
            }
            node = root['children'].find(c);
            if (node) {
                node['count'] += 1;
            } else {
                node = {'count': 1, 'children': {});
                root['children'][c] = node;
            }
        }
        return count + root['children'].size();
    }
};
